"use strict";

const express = require("express");
const { neon } = require("@neondatabase/serverless");
const cookieSession = require("cookie-session");
const adminTokens = new Set(); // in-memory valid tokens
const crypto = require("crypto");
const path = require("path");
const fs = require("fs");

const app = express();
const PORT = process.env.PORT || 3000;
const DB_URL = process.env.CANVAS_DATABASE_URL;
if (!DB_URL) { console.error("[canvas] FATAL: CANVAS_DATABASE_URL not set"); process.exit(1); }
const sql = neon(DB_URL);

// ── Middleware ────────────────────────────────────────────────────────────────
app.use(express.json({ limit: "10mb" }));
app.use(express.urlencoded({ extended: true, limit: "10mb" }));

// Apply cookie-session only to admin routes
const adminSession = cookieSession({
  name: "canvas_admin",
  keys: [process.env.ADMIN_PASSWORD || "canvas-secret"],
  maxAge: 8 * 60 * 60 * 1000,
});

// Token-based auth middleware for proxy-friendly admin access
function requireAdminToken(req, res, next) {
  const auth = req.headers["authorization"] || "";
  const token = auth.replace("Bearer ", "").trim();
  if (token && adminTokens.has(token)) return next();
  // Fall back to cookie-session for direct Render access
  if (req.session && req.session.admin) return next();
  res.status(401).json({ error: "Unauthorized" });
}

// ── Schema ────────────────────────────────────────────────────────────────────
async function ensureSchema() {
  await sql`CREATE TABLE IF NOT EXISTS canvas_attendees (
    id SERIAL PRIMARY KEY,
    session_id VARCHAR(32) UNIQUE NOT NULL,
    first_name VARCHAR(100),
    last_name VARCHAR(100),
    email VARCHAR(255),
    created_at BIGINT NOT NULL
  )`;
  await sql`CREATE TABLE IF NOT EXISTS canvas_artworks (
    id SERIAL PRIMARY KEY,
    session_id VARCHAR(32) REFERENCES canvas_attendees(session_id) ON DELETE CASCADE,
    png_data TEXT NOT NULL,
    created_at BIGINT NOT NULL
  )`;
  await sql`CREATE TABLE IF NOT EXISTS canvas_stickers (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    image_data TEXT NOT NULL,
    mime_type VARCHAR(50) NOT NULL,
    created_at BIGINT NOT NULL
  )`;
  await sql`CREATE TABLE IF NOT EXISTS canvas_config (
    id SERIAL PRIMARY KEY,
    text_colors JSONB NOT NULL DEFAULT '["#ffffff","#000000","#00aae8","#cccccc"]'
  )`;
  // Seed default config row if empty
  const cfg = await sql`SELECT id FROM canvas_config LIMIT 1`;
  if (!cfg.length) {
    await sql`INSERT INTO canvas_config (text_colors) VALUES ('["#ffffff","#000000","#00aae8","#cccccc"]')`;
  }
  await sql`CREATE TABLE IF NOT EXISTS canvas_events (
    id SERIAL PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    slug VARCHAR(100) UNIQUE NOT NULL,
    active BOOLEAN NOT NULL DEFAULT true,
    created_at BIGINT NOT NULL
  )`;
  await sql`CREATE TABLE IF NOT EXISTS canvas_kiosks (
    id SERIAL PRIMARY KEY,
    event_id INTEGER REFERENCES canvas_events(id) ON DELETE CASCADE,
    kiosk_number INTEGER NOT NULL,
    token VARCHAR(12) UNIQUE NOT NULL,
    created_at BIGINT NOT NULL
  )`;
  // Add kiosk_id to attendees if not exists
  await sql`ALTER TABLE canvas_attendees ADD COLUMN IF NOT EXISTS kiosk_id INTEGER REFERENCES canvas_kiosks(id)`;
  // Add event_id to attendees if not exists  
  await sql`ALTER TABLE canvas_attendees ADD COLUMN IF NOT EXISTS event_id INTEGER REFERENCES canvas_events(id)`;
  console.log("[canvas] Schema ready");
}

// ── Auth helpers ──────────────────────────────────────────────────────────────
function requireAdmin(req, res, next) {
  // Check bearer token in header (proxy-friendly fetch requests)
  const auth = req.headers["authorization"] || "";
  const headerToken = auth.replace("Bearer ", "").trim();
  if (headerToken && adminTokens.has(headerToken)) return next();
  // Check token in query param (initial page load after login)
  const queryToken = req.query.token || "";
  if (queryToken && adminTokens.has(queryToken)) return next();
  // Fall back to cookie session (direct Render URL)
  if (req.session && req.session.admin) return next();
  res.redirect("/admin/login");
}

// ── Registration ──────────────────────────────────────────────────────────────
app.get("/", (req, res) => res.send(renderRegistration()));

// Kiosk entry point — /k/:token
app.get("/k/:token", async (req, res) => {
  try {
    const rows = await sql`
      SELECT k.id as kiosk_id, k.kiosk_number, k.token, e.id as event_id, e.name as event_name
      FROM canvas_kiosks k JOIN canvas_events e ON e.id = k.event_id
      WHERE k.token = ${req.params.token} AND e.active = true
    `;
    if (!rows.length) return res.status(404).send("<h2>Kiosk not found or event is inactive.</h2>");
    const kiosk = rows[0];
    res.send(renderRegistration(kiosk));
  } catch (err) {
    res.status(500).send("<pre>Kiosk error: " + err.message + "</pre>");
  }
});

app.post("/register", async (req, res) => {
  try {
    const { first_name, last_name, email, kiosk_token } = req.body;
    if (!first_name || !email) return res.status(400).json({ error: "First name and email are required." });
    const sessionId = crypto.randomBytes(16).toString("hex");

    // Resolve kiosk if token provided
    let kioskId = null, eventId = null;
    if (kiosk_token) {
      const krows = await sql`SELECT k.id, k.event_id FROM canvas_kiosks k WHERE k.token = ${kiosk_token}`;
      if (krows.length) { kioskId = krows[0].id; eventId = krows[0].event_id; }
    }

    await sql`INSERT INTO canvas_attendees (session_id, first_name, last_name, email, created_at, kiosk_id, event_id)
      VALUES (${sessionId}, ${first_name.trim()}, ${(last_name || "").trim()}, ${email.trim()}, ${Date.now()}, ${kioskId}, ${eventId})`;

    const redirectBase = kiosk_token ? "/k/" + kiosk_token : "";
    res.json({ redirect: redirectBase + "/canvas/" + sessionId });
  } catch (err) {
    console.error("[canvas] /register error:", err.message);
    res.status(500).json({ error: err.message });
  }
});

// ── Canvas experience ─────────────────────────────────────────────────────────
async function serveCanvas(req, res, sessionId) {
  try {
    const rows = await sql`SELECT * FROM canvas_attendees WHERE session_id = ${sessionId}`;
    if (!rows.length) return res.redirect("/");
    const attendee = rows[0];
    const stickers = await sql`SELECT id, name, image_data, mime_type FROM canvas_stickers ORDER BY created_at ASC`;
    const cfgRows = await sql`SELECT text_colors FROM canvas_config LIMIT 1`;
    const textColors = cfgRows.length ? cfgRows[0].text_colors : ["#ffffff","#000000","#00aae8","#cccccc"];
    res.send(renderCanvas(attendee, stickers, textColors));
  } catch (err) {
    console.error("[canvas] /canvas error:", err.message);
    res.status(500).send("<pre>Canvas error: " + err.message + "</pre>");
  }
}
app.get("/canvas/:sessionId", (req, res) => serveCanvas(req, res, req.params.sessionId));
app.get("/k/:token/canvas/:sessionId", (req, res) => serveCanvas(req, res, req.params.sessionId));

// ── AI Background generation ──────────────────────────────────────────────────
app.post("/canvas/:sessionId/generate", async (req, res) => {
  const { prompt } = req.body;
  if (!prompt) return res.status(400).json({ error: "Prompt required" });

  const falKey = process.env.FAL_API_KEY;
  if (!falKey) return res.status(500).json({ error: "FAL_API_KEY not configured" });

  try {
    // Inject current Intel logo (post-2020 rebrand ONLY — absolutely no swoosh, oval, or circle)
    const enhancedPrompt = `${prompt}. Somewhere in the background of the scene — on a building, billboard, or sign — show the Intel logo. CRITICAL: the Intel logo is ONLY the lowercase word "intel" in plain white sans-serif text on a solid blue rectangular background. There is NO oval shape. There is NO circle. There is NO swoosh. There is NO ring around the text. There is NO ellipse. The letter i has a small dark square dot above it, not a circular one. The logo is flat, minimal, and typographic only. Any version of the Intel logo with an oval, circle, ellipse, or swoosh shape is the OLD logo and must NOT be used. This is a secondary background detail, not the focal point of the image.`;

    const falRes = await fetch("https://fal.run/fal-ai/flux-pro", {
      method: "POST",
      headers: { "Authorization": `Key ${falKey}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        prompt: enhancedPrompt,
        image_size: { width: 1024, height: 1024 },
        num_inference_steps: 28,
        guidance_scale: 3.5,
        num_images: 1,
        output_format: "jpeg",
      }),
    });

    if (!falRes.ok) {
      const err = await falRes.text();
      return res.status(500).json({ error: `Flux API error: ${err.slice(0, 200)}` });
    }

    const data = await falRes.json();
    const imageUrl = data.images?.[0]?.url;
    if (!imageUrl) return res.status(500).json({ error: "No image returned from Flux" });

    // Fetch and return as base64 data URL
    const imgRes = await fetch(imageUrl);
    const buffer = await imgRes.arrayBuffer();
    const b64 = Buffer.from(buffer).toString("base64");
    const dataUrl = `data:image/jpeg;base64,${b64}`;
    res.json({ dataUrl });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Save artwork ──────────────────────────────────────────────────────────────
app.post("/canvas/:sessionId/save", async (req, res) => {
  const { png } = req.body; // base64 PNG from html2canvas at 800x800
  if (!png) return res.status(400).json({ error: "No image data" });

  const rows = await sql`SELECT * FROM canvas_attendees WHERE session_id = ${req.params.sessionId}`;
  if (!rows.length) return res.status(404).json({ error: "Session not found" });
  const attendee = rows[0];

  try {
    // Upscale to 3000x3000 for heat transfer print quality using sharp
    const sharp = require("sharp");
    const base64Data = png.replace(/^data:image\/\w+;base64,/, "");
    const inputBuffer = Buffer.from(base64Data, "base64");
    const upscaled = await sharp(inputBuffer)
      .resize(3000, 3000, { kernel: sharp.kernel.lanczos3 })
      .png({ quality: 100 })
      .toBuffer();
    const finalBase64 = upscaled.toString("base64");

    // Delete any previous artwork for this session
    await sql`DELETE FROM canvas_artworks WHERE session_id = ${req.params.sessionId}`;
    await sql`INSERT INTO canvas_artworks (session_id, png_data, created_at)
      VALUES (${req.params.sessionId}, ${finalBase64}, ${Date.now()})`;

    // Generate QR code pointing to download
    const QRCode = require("qrcode");
    const downloadUrl = `${req.protocol}://${req.get("host")}/download/${req.params.sessionId}`;
    const qrDataUrl = await QRCode.toDataURL(downloadUrl, { width: 300, margin: 2 });

    res.json({ qrCode: qrDataUrl, downloadUrl, name: attendee.first_name });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Download ──────────────────────────────────────────────────────────────────
app.get("/download/:sessionId", async (req, res) => {
  const rows = await sql`
    SELECT a.png_data, att.first_name, att.last_name
    FROM canvas_artworks a
    JOIN canvas_attendees att ON att.session_id = a.session_id
    WHERE a.session_id = ${req.params.sessionId}
    ORDER BY a.created_at DESC LIMIT 1
  `;
  if (!rows.length) return res.status(404).send("Artwork not found");
  const { png_data, first_name, last_name } = rows[0];
  const buffer = Buffer.from(png_data, "base64");
  const filename = `canvas-${first_name}-${last_name || "art"}.png`.replace(/\s+/g, "-").toLowerCase();
  res.setHeader("Content-Type", "image/png");
  res.setHeader("Content-Disposition", `attachment; filename="${filename}"`);
  res.send(buffer);
});

// ── Event management ──────────────────────────────────────────────────────────
app.post("/admin/events", adminSession, requireAdmin, async (req, res) => {
  console.log("[events] body:", JSON.stringify(req.body), "contentType:", req.headers["content-type"]);
  const { name, kiosk_count } = req.body;
  if (!name) return res.status(400).json({ error: "name is required", body: req.body });
  const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
  const count = Math.min(10, Math.max(1, parseInt(kiosk_count) || 1));
  const token = req.query.token || "";
  try {
    const evtRows = await sql`INSERT INTO canvas_events (name, slug, active, created_at) VALUES (${name.trim()}, ${slug}, true, ${Date.now()}) RETURNING id`;
    const eventId = evtRows[0].id;
    for (let i = 1; i <= count; i++) {
      const kToken = require("crypto").randomBytes(6).toString("hex");
      await sql`INSERT INTO canvas_kiosks (event_id, kiosk_number, token, created_at) VALUES (${eventId}, ${i}, ${kToken}, ${Date.now()})`;
    }
  } catch(err) {
    console.error("[canvas] create event error:", err.message);
    return res.status(500).json({ error: err.message });
  }
  res.json({ ok: true });
});

app.post("/admin/events/:id/delete", adminSession, requireAdmin, async (req, res) => {
  await sql`DELETE FROM canvas_events WHERE id = ${req.params.id}`;
  res.redirect("/admin?token=" + (req.query.token || ""));
});

app.post("/admin/events/:id/toggle", adminSession, requireAdmin, async (req, res) => {
  await sql`UPDATE canvas_events SET active = NOT active WHERE id = ${req.params.id}`;
  res.redirect("/admin?token=" + (req.query.token || ""));
});

// ── Text color config ─────────────────────────────────────────────────────────
app.post("/admin/config/colors", adminSession, requireAdmin, async (req, res) => {
  const colors = [req.body.color1, req.body.color2, req.body.color3, req.body.color4]
    .map(c => (c && /^#[0-9a-fA-F]{6}$/.test(c) ? c : "#ffffff"));
  await sql`UPDATE canvas_config SET text_colors = ${JSON.stringify(colors)}::jsonb`;
  res.redirect("/admin?token=" + (req.query.token || ""));
});

// ── Admin login ───────────────────────────────────────────────────────────────
app.get("/admin/login", adminSession, (req, res) => res.send(renderAdminLogin()));

app.post("/admin/login", adminSession, (req, res) => {
  const { password } = req.body;
  if (password === (process.env.ADMIN_PASSWORD || "canvas")) {
    req.session.admin = true;
    // Also issue a bearer token for proxy-friendly auth
    const token = crypto.randomBytes(32).toString("hex");
    adminTokens.add(token);
    // Clean up old tokens after 8 hours
    setTimeout(() => adminTokens.delete(token), 8 * 60 * 60 * 1000);
    res.json({ redirect: "/admin", token });
  } else {
    res.status(401).json({ error: "Invalid password" });
  }
});

app.get("/admin/logout", adminSession, (req, res) => {
  req.session = null;
  res.redirect("/admin/login");
});

// ── Admin dashboard ───────────────────────────────────────────────────────────
app.get("/admin", adminSession, requireAdmin, async (req, res) => {
  const stickers = await sql`SELECT * FROM canvas_stickers ORDER BY created_at DESC`;
  const artworks = await sql`
    SELECT a.id, a.session_id, a.png_data, a.created_at, att.first_name, att.last_name, att.email
    FROM canvas_artworks a
    JOIN canvas_attendees att ON att.session_id = a.session_id
    ORDER BY a.created_at DESC
  `;
  const cfgRows = await sql`SELECT text_colors FROM canvas_config LIMIT 1`;
  const colors = cfgRows.length ? cfgRows[0].text_colors : ["#ffffff","#000000","#00aae8","#cccccc"];
  const events = await sql`
    SELECT e.*, COUNT(k.id) as kiosk_count
    FROM canvas_events e LEFT JOIN canvas_kiosks k ON k.event_id = e.id
    GROUP BY e.id ORDER BY e.created_at DESC
  `;
  const kiosks = await sql`
    SELECT k.*, e.name as event_name
    FROM canvas_kiosks k JOIN canvas_events e ON e.id = k.event_id
    ORDER BY e.created_at DESC, k.kiosk_number ASC
  `;
  res.send(renderAdmin(stickers, artworks, colors, req, events, kiosks));
});

// Sticker upload
app.post("/admin/stickers", adminSession, requireAdmin, async (req, res) => {
  const Busboy = require("busboy");
  const busboy = Busboy({ headers: req.headers, limits: { fileSize: 2 * 1024 * 1024 } });
  let name = "";
  let fileData = null;
  let mimeType = "";

  busboy.on("field", (fieldname, val) => { if (fieldname === "name") name = val.trim(); });
  busboy.on("file", (fieldname, file, info) => {
    mimeType = info.mimeType;
    const chunks = [];
    file.on("data", chunk => chunks.push(chunk));
    file.on("end", () => { fileData = Buffer.concat(chunks).toString("base64"); });
  });
  busboy.on("finish", async () => {
    if (!name || !fileData) return res.redirect("/admin");
    await sql`INSERT INTO canvas_stickers (name, image_data, mime_type, created_at)
      VALUES (${name}, ${fileData}, ${mimeType}, ${Date.now()})`;
    res.redirect("/admin");
  });
  req.pipe(busboy);
});

// Sticker delete
app.post("/admin/stickers/:id/delete", adminSession, requireAdmin, async (req, res) => {
  await sql`DELETE FROM canvas_stickers WHERE id = ${req.params.id}`;
  res.redirect("/admin");
});

// Gallery download all
app.get("/admin/gallery/download", adminSession, requireAdmin, async (req, res) => {
  const archiver = require("archiver");
  const rows = await sql`
    SELECT a.png_data, att.first_name, att.last_name, a.created_at
    FROM canvas_artworks a
    JOIN canvas_attendees att ON att.session_id = a.session_id
    ORDER BY a.created_at DESC
  `;
  res.setHeader("Content-Type", "application/zip");
  res.setHeader("Content-Disposition", "attachment; filename=\"canvas-artworks.zip\"");
  const archive = archiver("zip");
  archive.pipe(res);
  for (const row of rows) {
    const buffer = Buffer.from(row.png_data, "base64");
    const filename = `${row.first_name}-${row.last_name || "art"}-${row.created_at}.png`.replace(/\s+/g, "-").toLowerCase();
    archive.append(buffer, { name: filename });
  }
  archive.finalize();
});

